import React, { useState, useEffect } from 'react';
import './CookieBanner.css';

export default function CookieBanner() {
  const [visible, setVisible] = useState(false);
  const [showDetails, setShowDetails] = useState(false);
  const [preferences, setPreferences] = useState({
    analytics: false,
    marketing: false,
    functional: false,
  });

  useEffect(() => {
    const consent = localStorage.getItem('ame_cookie_consent');
    if (!consent) {
      const timer = setTimeout(() => setVisible(true), 600);
      return () => clearTimeout(timer);
    }
  }, []);

  const saveConsent = (type, prefs) => {
    localStorage.setItem(
      'ame_cookie_consent',
      JSON.stringify({ type, prefs, date: new Date().toISOString() })
    );
    setVisible(false);
  };

  const handleAcceptAll = () => {
    const all = { analytics: true, marketing: true, functional: true };
    setPreferences(all);
    saveConsent('all', all);
  };

  const handleRejectAll = () => {
    saveConsent('necessary', { analytics: false, marketing: false, functional: false });
  };

  const handleSavePreferences = () => {
    saveConsent('custom', preferences);
  };

  const toggle = (key) =>
    setPreferences((prev) => ({ ...prev, [key]: !prev[key] }));

  if (!visible) return null;

  return (
    <div className={`cb ${visible ? 'cb--in' : ''}`}>
      <div className="cb__bar">

        {!showDetails ? (
          <>
            <p className="cb__text">
              Usamos cookies para melhorar sua experiência, analisar o tráfego e personalizar conteúdo,
              em conformidade com a <strong>LGPD (Lei nº 13.709/2018)</strong>.{' '}
              <a href="/politica-de-privacidade" target="_blank" rel="noopener noreferrer">
                Saiba mais
              </a>
            </p>

            <div className="cb__actions">
              <button className="cb__btn cb__btn--ghost" onClick={() => setShowDetails(true)}>
                Gerenciar
              </button>
              <button className="cb__btn cb__btn--outline" onClick={handleRejectAll}>
                Recusar
              </button>
              <button className="cb__btn cb__btn--primary" onClick={handleAcceptAll}>
                Aceitar todos
              </button>
            </div>
          </>
        ) : (
          <>
            <div className="cb__details">
              <p className="cb__details-title">Preferências de cookies</p>

              <div className="cb__toggles">
                <div className="cb__toggle-item">
                  <div className="cb__toggle-info">
                    <span className="cb__toggle-label">Essenciais</span>
                    <span className="cb__toggle-desc">Necessários para o funcionamento do site.</span>
                  </div>
                  <span className="cb__always">Sempre ativo</span>
                </div>

                {[
                  { key: 'analytics', label: 'Analíticos', desc: 'Métricas de uso e desempenho (Google Analytics).' },
                  { key: 'functional', label: 'Funcionais', desc: 'Recursos aprimorados como formulários e chat.' },
                  { key: 'marketing', label: 'Marketing', desc: 'Anúncios personalizados e campanhas.' },
                ].map(({ key, label, desc }) => (
                  <div key={key} className="cb__toggle-item">
                    <div className="cb__toggle-info">
                      <span className="cb__toggle-label">{label}</span>
                      <span className="cb__toggle-desc">{desc}</span>
                    </div>
                    <button
                      className={`cb__switch ${preferences[key] ? 'cb__switch--on' : ''}`}
                      onClick={() => toggle(key)}
                      aria-pressed={preferences[key]}
                    >
                      <span className="cb__thumb" />
                    </button>
                  </div>
                ))}
              </div>
            </div>

            <div className="cb__actions">
              <button className="cb__btn cb__btn--ghost" onClick={() => setShowDetails(false)}>
                ← Voltar
              </button>
              <button className="cb__btn cb__btn--outline" onClick={handleRejectAll}>
                Recusar
              </button>
              <button className="cb__btn cb__btn--outline" onClick={handleSavePreferences}>
                Salvar seleção
              </button>
              <button className="cb__btn cb__btn--primary" onClick={handleAcceptAll}>
                Aceitar todos
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
